import{_ as a,o as t,c as r,a2 as i}from"./chunks/framework.OWFDNrRT.js";const p=JSON.parse('{"title":"ADR-002: Declarative-First Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-002-declarative-first-architecture.md","filePath":"adr/ADR-002-declarative-first-architecture.md","lastUpdated":1773460793000}'),o={name:"adr/ADR-002-declarative-first-architecture.md"};function n(s,e,l,c,d,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-002-declarative-first-architecture" tabindex="-1">ADR-002: Declarative-First Architecture <a class="header-anchor" href="#adr-002-declarative-first-architecture" aria-label="Permalink to &quot;ADR-002: Declarative-First Architecture&quot;">​</a></h1><p><strong>Status</strong>: Accepted <strong>Date</strong>: 2026-03-09 <strong>Deciders</strong>: kooshapari</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>DINO modding requires reverse engineering and ECS-aware patching. Without guardrails, agents will write arbitrary imperative C# patches against game internals, creating unmaintainable code.</p><p>The best modding ecosystems (Factorio, RimWorld, Minecraft Bedrock) all use declarative-first authoring: easy things are data, hard things are code, invasive things are controlled patches.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>DINOForge adopts a <strong>5-layer content model</strong>:</p><h3 id="layer-1-content-packs-declarative" tabindex="-1">Layer 1: Content Packs (Declarative) <a class="header-anchor" href="#layer-1-content-packs-declarative" aria-label="Permalink to &quot;Layer 1: Content Packs (Declarative)&quot;">​</a></h3><p>JSON/YAML/TOML data defining factions, units, weapons, projectiles, audio, UI labels, tech trees, AI params, spawn tables, VFX references.</p><h3 id="layer-2-asset-packs-declarative-binary" tabindex="-1">Layer 2: Asset Packs (Declarative + Binary) <a class="header-anchor" href="#layer-2-asset-packs-declarative-binary" aria-label="Permalink to &quot;Layer 2: Asset Packs (Declarative + Binary)&quot;">​</a></h3><p>Bundled art/audio/prefab references with explicit manifests and compatibility metadata.</p><h3 id="layer-3-code-plugins-narrow-api" tabindex="-1">Layer 3: Code Plugins (Narrow API) <a class="header-anchor" href="#layer-3-code-plugins-narrow-api" aria-label="Permalink to &quot;Layer 3: Code Plugins (Narrow API)&quot;">​</a></h3><p>C# plugin API for custom systems, ECS queries, hooks, behaviors. Must go through SDK interfaces.</p><h3 id="layer-4-patch-layer-controlled-marked-unsafe" tabindex="-1">Layer 4: Patch Layer (Controlled, Marked Unsafe) <a class="header-anchor" href="#layer-4-patch-layer-controlled-marked-unsafe" aria-label="Permalink to &quot;Layer 4: Patch Layer (Controlled, Marked Unsafe)&quot;">​</a></h3><p>Controlled patch points for base game modifications. Fenced off, clearly marked as high-fragility. Harmony/BepInEx equivalent.</p><h3 id="layer-5-tooling" tabindex="-1">Layer 5: Tooling <a class="header-anchor" href="#layer-5-tooling" aria-label="Permalink to &quot;Layer 5: Tooling&quot;">​</a></h3><p>CLI + GUI tools: create, validate, build, diff, package, install, generate docs, run compat tests.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li>Agents mostly author YAML/JSON manifests and content bundles</li><li>Raw imperative C# plugin code is rare and goes through review gates</li><li>Pack compiler validates everything before runtime</li><li>Most mods become data-driven, not code-driven</li><li>&quot;preferred&quot; = register faction with units/costs/tech/projectiles/icons/audio/waves</li><li>&quot;not preferred&quot; = write custom imperative patch code editing 14 engine systems manually</li></ul>',19)])])}const g=a(o,[["render",n]]);export{p as __pageData,g as default};
